import os
import secrets
import imghdr
from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename
from PIL import Image
import io

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = '/var/uploads/profile_pictures'  # Outside web root
MAX_FILE_SIZE = 5 * 1024 * 1024  # 5MB
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'webp'}
ALLOWED_MIME_TYPES = {'image/png', 'image/jpeg', 'image/gif', 'image/webp'}
MAX_IMAGE_PIXELS = 4096 * 4096  # Prevent decompression bombs

# Create upload directory if it doesn't exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE


def validate_image_content(file_stream):
    """Validate image content using multiple methods"""
    try:
        # Reset stream position
        file_stream.seek(0)
        
        # Check using imghdr (magic bytes)
        header = file_stream.read(512)
        file_stream.seek(0)
        image_type = imghdr.what(None, header)
        
        if image_type not in ['png', 'jpeg', 'gif', 'webp']:
            return False, "Invalid image format detected"
        
        # Validate with PIL and check for decompression bombs
        file_stream.seek(0)
        try:
            img = Image.open(file_stream)
            img.verify()  # Verify it's actually an image
            
            # Re-open for further processing (verify() closes the file)
            file_stream.seek(0)
            img = Image.open(file_stream)
            
            # Check dimensions
            width, height = img.size
            if width * height > MAX_IMAGE_PIXELS:
                return False, "Image dimensions too large"
            
            # Check format matches
            if img.format.lower() not in ['png', 'jpeg', 'gif', 'webp']:
                return False, "Unsupported image format"
                
        except (IOError, SyntaxError, Image.DecompressionBombError) as e:
            return False, f"Invalid or corrupted image: {str(e)}"
        
        file_stream.seek(0)
        return True, image_type
        
    except Exception as e:
        return False, f"Validation error: {str(e)}"


def generate_secure_filename(original_filename, image_type):
    """Generate a secure random filename"""
    # Generate random filename
    random_name = secrets.token_urlsafe(16)
    
    # Map image type to extension
    extension_map = {
        'jpeg': 'jpg',
        'png': 'png',
        'gif': 'gif',
        'webp': 'webp'
    }
    
    extension = extension_map.get(image_type, 'jpg')
    return f"{random_name}.{extension}"


def sanitize_and_resize_image(file_stream, max_size=(1024, 1024)):
    """Sanitize and resize image to prevent various attacks"""
    try:
        file_stream.seek(0)
        img = Image.open(file_stream)
        
        # Convert to RGB if necessary (removes potential exploits in other modes)
        if img.mode not in ('RGB', 'RGBA'):
            img = img.convert('RGB')
        
        # Resize if too large
        img.thumbnail(max_size, Image.Resampling.LANCZOS)
        
        # Save to bytes buffer with controlled format
        output = io.BytesIO()
        
        # Save as JPEG or PNG only (most secure formats)
        if img.mode == 'RGBA':
            img.save(output, format='PNG', optimize=True)
            format_ext = 'png'
        else:
            img.save(output, format='JPEG', quality=85, optimize=True)
            format_ext = 'jpg'
        
        output.seek(0)
        return output, format_ext
        
    except Exception as e:
        raise ValueError(f"Image processing failed: {str(e)}")


@app.route('/upload-profile-picture', methods=['POST'])
def upload_profile_picture():
    """Secure profile picture upload endpoint"""
    
    # Check if file is in request
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    # Check if file was selected
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    # Check file size (additional check beyond MAX_CONTENT_LENGTH)
    file.seek(0, os.SEEK_END)
    file_size = file.tell()
    file.seek(0)
    
    if file_size > MAX_FILE_SIZE:
        return jsonify({'error': f'File too large. Maximum size is {MAX_FILE_SIZE} bytes'}), 400
    
    if file_size == 0:
        return jsonify({'error': 'Empty file'}), 400
    
    # Validate MIME type from request
    content_type = file.content_type
    if content_type not in ALLOWED_MIME_TYPES:
        return jsonify({'error': 'Invalid file type. Only images allowed'}), 400
    
    # Validate actual file content (magic bytes and structure)
    is_valid, result = validate_image_content(file.stream)
    
    if not is_valid:
        return jsonify({'error': result}), 400
    
    image_type = result
    
    try:
        # Sanitize and resize image
        processed_image, format_ext = sanitize_and_resize_image(file.stream)
        
        # Generate secure filename (server-side, not user-controlled)
        secure_name = generate_secure_filename(file.filename, format_ext)
        
        # Construct safe file path
        file_path = os.path.join(UPLOAD_FOLDER, secure_name)
        
        # Ensure the path is within UPLOAD_FOLDER (prevent path traversal)
        real_upload_folder = os.path.realpath(UPLOAD_FOLDER)
        real_file_path = os.path.realpath(file_path)
        
        if not real_file_path.startswith(real_upload_folder):
            return jsonify({'error': 'Invalid file path'}), 400
        
        # Save the processed image
        with open(file_path, 'wb') as f:
            f.write(processed_image.read())
        
        # Set restrictive permissions (owner read/write only)
        os.chmod(file_path, 0o600)
        
        return jsonify({
            'message': 'Profile picture uploaded successfully',
            'filename': secure_name,
            'size': os.path.getsize(file_path)
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Upload failed'}), 500


@app.route('/profile-picture/<filename>', methods=['GET'])
def get_profile_picture(filename):
    """Serve profile picture with validation"""
    
    # Validate filename format (only alphanumeric, dash, underscore, and extension)
    secure_name = secure_filename(filename)
    if secure_name != filename or '..' in filename:
        return jsonify({'error': 'Invalid filename'}), 400
    
    # Construct and validate path
    file_path = os.path.join(UPLOAD_FOLDER, secure_name)
    real_upload_folder = os.path.realpath(UPLOAD_FOLDER)
    real_file_path = os.path.realpath(file_path)
    
    if not real_file_path.startswith(real_upload_folder):
        return jsonify({'error': 'Invalid file path'}), 400
    
    if not os.path.exists(file_path):
        return jsonify({'error': 'File not found'}), 404
    
    return send_from_directory(UPLOAD_FOLDER, secure_name, mimetype='image/jpeg')


